mapper.select:
select
id, order_id, user_id, commodity_id, commodity_name, commodity_desc, bandwidth, business_suitable, category_id,
category_name, category_desc, is_deleted, create_user, update_user, create_time, update_time
from order_information_snapshot

    1 = 1 and is_deleted = 0

        and id = #{id}


        and order_id = #{orderId}


        and user_id = #{userId}


        and commodity_id = #{commodityId}


        and commodity_name = #{commodityName}


        and commodity_desc = #{commodityDesc}


        and bandwidth = #{bandwidth}


        and business_suitable = #{businessSuitable}


        and category_id = #{categoryId}


        and category_name = #{categoryName}


        and category_desc = #{categoryDesc}


        and is_deleted = #{isDeleted}


        and create_user = #{createUser}


        and update_user = #{updateUser}


        and create_time = #{createTime}


        and update_time = #{updateTime}

